def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for m in range(1, 8):
                inner_sum = 0
                for n in range(1, m+1):
                    inner_sum += np.cos(ratio * n * np.pi) / (n + 1)
                score += inner_sum * (20 / m)
            if cap % 3 == 0:
                for p in range(1, int(cap // 2) + 1):
                    if cap % p == 0 and p % 2 != 0:
                        score += (p ** 1.2) * 0.5
            if ratio < 0.05:
                score *= 1.5
        elif 0.1 <= ratio < 0.3:
            score += np.tanh(ratio * 10) * 18
            for q in range(1, 5):
                if (q * cap) % 5 == 0:
                    score += np.sqrt(q) * 1.3
                else:
                    score -= (q / (1 + ratio)) * 0.4
            if int(cap) % 5 == 0:
                score += 7
        elif 0.3 <= ratio <= 0.6:
            base = np.log1p(ratio * 50) * 8
            factorial_sum = 0
            for d in range(1, 7):
                factorial = 1
                for f in range(1, d + 1):
                    factorial *= f
                factorial_sum += ((ratio * d) ** d) / factorial
            score += base + factorial_sum * 5
            if cap > 15:
                for e in range(2, int(min(12, cap))):
                    if cap % e == 0 and e % 4 == 0:
                        score += np.log1p(e) * 3
            if ratio > 0.55:
                score += (0.8 - ratio) * 20
        elif 0.6 < ratio <= 0.9:
            score += (1 / (1 + np.exp(-10*(ratio-0.75)))) * 35
            prime_count = 0
            for g in range(2, 12):
                is_prime = True
                for h in range(2, int(np.sqrt(g)) + 1):
                    if g % h == 0:
                        is_prime = False
                        break
                if is_prime:
                    prime_count += 1
                    score += g * 0.9
            score += prime_count * 2
            if cap % 10 == 0:
                score *= 1.1
        elif 0.9 < ratio <= 1.1:
            for u in range(1, 10):
                score += np.sin(ratio * np.pi * u) * (12 / u)
            if ratio > 1.05:
                score -= (ratio - 1) * 30
            if int(cap) % 11 == 0:
                score += 8
            if int(cap) % 13 == 0:
                score -= 5
        elif 1.1 < ratio <= 2:
            penalty = 0
            chunk_size = int(cap // 5) if cap >= 5 else 1
            for i in range(1, chunk_size + 1):
                if cap % i == 0:
                    penalty += i ** 1.8
            score -= penalty / (chunk_size + 2)
            fract_part = ratio - int(ratio)
            for j in range(1, 8):
                mod_val = (fract_part * j * 150) % 9
                score += (mod_val / 9) * 5
            score += (1.5 - ratio) * 25
            if ratio > 1.7 and int(cap) % 14 == 0:
                score += 12
        else:
            penalty = 0
            chunk_size = max(1, int(cap // 3))
            for x in range(1, chunk_size + 1):
                if cap % x == 0:
                    penalty += np.power(x, 2) * (0.5 + (x % 4) * 0.1)
            score -= penalty / (chunk_size + 3)
            fract_part = ratio - int(ratio)
            for y in range(1, 10):
                mod_val = (fract_part * y * 200) % 11
                score += (mod_val / 11) * 6
            score += (ratio - 2) * 60
            if ratio > 4:
                for k in range(1, int(cap // 3) + 1):
                    if k % 6 == 0:
                        score += np.cos(k) * 4
        if int(cap) % 5 == 0:
            score *= 0.9
        if int(cap) % 12 == 0 and ratio < 1.5:
            score *= 1.12
        if ratio > 3 and int(cap) % 15 == 0:
            score += 15
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 300)
    return priorities
